script:
{% assign tag_to_watch_for = options.tag_to_watch_for__required | downcase %}
{% assign invitation_email_subject = options.invitation_email_subject__required %}
{% assign invitation_email_body = options.invitation_email_body__multiline_required %}

{% if event.topic == "shopify/customer/tags_added" %}
  {% comment %}
    -- check tags before querying the customer with GraphQL, so we know if the monitored tag was just added
    -- note: this webhook uses a tags array, unlike most other webhooks with tags
  {% endcomment %}

  {% if event.preview %}
    {% capture customer_json %}
      {
        "customerId": "gid://shopify/Customer/1234567890",
        "tags": {{ array | push: tag_to_watch_for | json }}
      }
    {% endcapture %}

    {% assign customer = customer_json | parse_json %}
  {% endif %}

  {% assign added_tags = customer.tags | json | downcase | parse_json %}

  {% unless added_tags contains tag_to_watch_for %}
    {% break %}
  {% endunless %}

  {% comment %}
    -- get customer data
  {% endcomment %}

  {% capture query %}
    query {
      customer(id: {{ customer.customerId | json }}) {
        id
        displayName
        defaultEmailAddress {
          emailAddress
        }
        state
        tags
      }
    }
  {% endcapture %}

  {% assign result = query | shopify %}

  {% if event.preview %}
    {% capture result_json %}
      {
        "data": {
          "customer": {
            "id": "gid://shopify/Customer/1234567890",
            "state": "DISABLED"
          }
        }
      }
    {% endcapture %}

    {% assign result = result_json | parse_json %}
  {% endif %}

  {% assign customer = result.data.customer %}

  {% unless event.preview %}
    {% log customer: customer %}
  {% endunless %}

  {% unless customer.state == "DISABLED" %}
    {% log "Customer state is not 'DISABLED', so an account invite will not be sent." %}
    {% break %}
  {% endunless %}

  {% action "shopify" %}
    mutation {
      customerSendAccountInviteEmail(
        customerId: {{ customer.id | json }}
        email: {
          subject: {{ invitation_email_subject | json }}
          customMessage: {{ invitation_email_body | json }}
        }
      ) {
        customer {
          id
          displayName
          defaultEmailAddress {
            emailAddress
          }
          state
        }
      }
    }
  {% endaction %}
{% endif %}
